            if (!visitedNodes.contains(nextNode) && visitedNodes.containsAll(nextNode.getPredecessors())) {
                orderedNodes.add(nextNode);
                visitedNodes.add(nextNode);
            }
        }
        i++;
    }

    return orderedNodes;
}

